// If LHS is icmp eq/ne (sub A B) C where C is known non-zero, then A != B.
// If A = ptrtoint(R0) and B = ptrtoint(R1), then R0 != R1.
if ((LPred == ICmpInst::ICMP_EQ || LPred == ICmpInst::ICMP_NE) &&
    match(L0, m_Sub(m_Value(A), m_Value(B)))) {
  // Check if L1 is known to be non-zero when LPred == ICMP_EQ,
  // or if L1 is zero when LPred == ICMP_NE.
  bool SubIsNonZero = false;
  if (LPred == ICmpInst::ICMP_EQ) {
    // icmp eq (sub A B) L1 implies (sub A B) != 0 if L1 doesn't contain 0
    ConstantRange L1Range = computeConstantRange(
